class Solution:
    def minimizeStringValue(self, s: str) -> str:
        result = []
        used = set()
        for char in s:
            if char == '?':
                for i in range(26):
                    letter = chr(i + ord('a'))
                    if letter not in used:
                        result.append(letter)
                        used.add(letter)
                        break
            else:
                result.append(char)
        return ''.join(result)

